package com.seaquake6324.civitas.infrastructure.entity;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.population.MaterializationLease;import java.util.UUID;import org.junit.jupiter.api.Test;
class MaterializationLeaseManagerTest{@Test void oneCitizenCannotAcquireTwoEntityLeases(){MaterializationLeaseManager.clear();UUID citizen=UUID.randomUUID(),lease=UUID.randomUUID(),entity=UUID.randomUUID();assertTrue(MaterializationLeaseManager.acquire(new MaterializationLease(citizen,lease,entity,1,10)));assertEquals(entity,MaterializationLeaseManager.lease(citizen).orElseThrow().entityId());assertTrue(MaterializationLeaseManager.acquire(new MaterializationLease(citizen,lease,entity,1,10)));assertFalse(MaterializationLeaseManager.acquire(new MaterializationLease(citizen,UUID.randomUUID(),UUID.randomUUID(),1,10)));MaterializationLeaseManager.release(citizen,lease,entity);assertTrue(MaterializationLeaseManager.acquire(new MaterializationLease(citizen,UUID.randomUUID(),UUID.randomUUID(),2,20)));MaterializationLeaseManager.revoke(citizen);assertFalse(MaterializationLeaseManager.active(citizen));MaterializationLeaseManager.clear();}}
